34: // Matches returns if the Attr matches the Rule.
35: func (r *Matcher) Matches() bool {
36: 	return r.scope() &&
37: 		r.operation() &&
38: 		r.group() &&
39: 		r.version() &&
40: 		r.resource()
41: }
