43: func exactOrWildcard(items []string, requested string) bool {
44: 	for _, item := range items {
45: 		if item == "*" {
46: 			return true
47: 		}
48: 		if item == requested {
49: 			return true
50: 		}
51: 	}
52: 
53: 	return false
54: }
