98: func splitResource(resSub string) (res, sub string) {
99: 	parts := strings.SplitN(resSub, "/", 2)
100: 	if len(parts) == 2 {
101: 		return parts[0], parts[1]
102: 	}
103: 	return parts[0], ""
104: }
