{
  "repo": "github.com/sg-evals/kubernetes--v1.32.0",
  "files": [
    {
      "path": "staging/src/k8s.io/apiserver/pkg/admission/chain.go",
      "role": "admission_chain",
      "description": "chainAdmissionHandler: the ordered list of all admission plugins. Admit() iterates handlers calling MutationInterface.Admit(); Validate() iterates calling ValidationInterface.Validate(). This is the top-level chain that sequences every plugin, including the two webhook plugins."
    },
    {
      "path": "staging/src/k8s.io/apiserver/pkg/admission/plugin/webhook/mutating/plugin.go",
      "role": "webhook_admission_controller",
      "description": "MutatingAdmissionWebhook plugin. Registers as 'MutatingAdmissionWebhook'. Admit() calls Webhook.Dispatch() which fans out to the mutating dispatcher. Also wires the configuration source (NewMutatingWebhookConfigurationManager) and the mutating dispatcherFactory."
    },
    {
      "path": "staging/src/k8s.io/apiserver/pkg/admission/plugin/webhook/validating/plugin.go",
      "role": "webhook_admission_controller",
      "description": "ValidatingAdmissionWebhook plugin. Registers as 'ValidatingAdmissionWebhook'. Validate() calls Webhook.Dispatch() which fans out to the validating dispatcher. Wires the configuration source (NewValidatingWebhookConfigurationManager) and the validating dispatcherFactory."
    },
    {
      "path": "staging/src/k8s.io/apiserver/pkg/admission/plugin/webhook/generic/webhook.go",
      "role": "webhook_call_dispatch",
      "description": "Webhook struct: the shared base for both mutating and validating plugins. Dispatch() is the central dispatch entry point: exempts admission-configuration resources, waits for readiness, fetches the live hook list from hookSource, then delegates to the concrete Dispatcher. ShouldCallHook() evaluates namespace selector, object selector, rules matching, and CEL match conditions to decide whether a given webhook should be invoked."
    },
    {
      "path": "staging/src/k8s.io/apiserver/pkg/admission/plugin/webhook/generic/interfaces.go",
      "role": "webhook_call_dispatch",
      "description": "Core interfaces for the dispatch layer: Dispatcher (Dispatch method called with the full hook list), Source (Webhooks()/HasSynced()), VersionedAttributeAccessor, and WebhookInvocation (carries the resolved resource/kind/subresource for a single hook call)."
    },
    {
      "path": "staging/src/k8s.io/apiserver/pkg/admission/plugin/webhook/mutating/dispatcher.go",
      "role": "webhook_call_dispatch",
      "description": "mutatingDispatcher: implements generic.Dispatcher for mutating webhooks. Dispatch() iterates all hooks, calls ShouldCallHook, then callAttrMutatingHook() which sends the AdmissionReview request, reads the response, applies JSON patches to the object, and handles reinvocation logic (IfNeeded policy)."
    },
    {
      "path": "staging/src/k8s.io/apiserver/pkg/admission/plugin/webhook/validating/dispatcher.go",
      "role": "webhook_call_dispatch",
      "description": "validatingDispatcher: implements generic.Dispatcher for validating webhooks. Dispatch() fans out all matching hooks concurrently (goroutines), collects results, and aggregates errors. callHook() sends the AdmissionReview request and processes the response."
    },
    {
      "path": "staging/src/k8s.io/apiserver/pkg/admission/plugin/webhook/request/admissionreview.go",
      "role": "admission_response_aggregation",
      "description": "Admission request/response serialization and verification. CreateAdmissionObjects() selects the correct AdmissionReview version (v1 or v1beta1) and builds the request object. CreateV1AdmissionReview() and CreateV1beta1AdmissionReview() populate the AdmissionRequest from admission.Attributes. VerifyAdmissionResponse() validates the webhook's response (UID match, GVK, patch/patchType consistency for mutating vs validating) and returns a normalized AdmissionResponse struct."
    },
    {
      "path": "staging/src/k8s.io/apiserver/pkg/admission/plugin/webhook/errors/statuserror.go",
      "role": "admission_response_aggregation",
      "description": "Response error aggregation helpers. ToStatusErr() converts a webhook-returned *metav1.Status into a *apierrors.StatusError with a standardized 'admission webhook X denied the request' message and enforces minimum HTTP 400 status. NewDryRunUnsupportedErr() produces the error when a webhook does not support dry-run."
    },
    {
      "path": "staging/src/k8s.io/apiserver/pkg/admission/plugin/webhook/accessors.go",
      "role": "webhook_accessor",
      "description": "WebhookAccessor interface and its two concrete implementations (mutatingWebhookAccessor, validatingWebhookAccessor). Provides a unified API over v1.MutatingWebhook and v1.ValidatingWebhook: GetRESTClient (lazy-initialised), GetCompiledMatcher (lazy CEL compilation), GetParsedNamespaceSelector/ObjectSelector (lazy label-selector parsing), and all scalar fields. hookClientConfigForWebhook() converts a WebhookAccessor into a webhookutil.ClientConfig."
    },
    {
      "path": "staging/src/k8s.io/apiserver/pkg/admission/configuration/mutating_webhook_manager.go",
      "role": "configuration_source",
      "description": "mutatingWebhookConfigurationManager: implements generic.Source for mutating webhooks. Watches MutatingWebhookConfiguration objects via an informer, caches per-configuration WebhookAccessor slices (to avoid CEL recompilation), and exposes Webhooks() / HasSynced(). Sorts configurations by name for deterministic ordering."
    },
    {
      "path": "staging/src/k8s.io/apiserver/pkg/admission/configuration/validating_webhook_manager.go",
      "role": "configuration_source",
      "description": "validatingWebhookConfigurationManager: implements generic.Source for validating webhooks. Mirrors the mutating manager but for ValidatingWebhookConfiguration objects."
    },
    {
      "path": "staging/src/k8s.io/apiserver/pkg/admission/configuration/configuration_manager.go",
      "role": "configuration_source",
      "description": "poller: a generic polling helper (used historically; the managers above now use informer-based synctrack.Lazy instead). Defines ErrNotReady / ErrDisabled sentinel errors and the bootstrap grace-period / failure-threshold logic for configuration readiness."
    },
    {
      "path": "staging/src/k8s.io/apiserver/pkg/admission/plugin/webhook/predicates/namespace/matcher.go",
      "role": "webhook_predicate",
      "description": "Namespace-selector predicate. MatchNamespaceSelector() resolves the namespace labels (from the informer cache or a live API call on cache miss) and tests them against the webhook's parsed NamespaceSelector. Called by generic.Webhook.ShouldCallHook()."
    },
    {
      "path": "staging/src/k8s.io/apiserver/pkg/admission/plugin/webhook/predicates/object/matcher.go",
      "role": "webhook_predicate",
      "description": "Object-selector predicate. MatchObjectSelector() tests the new and old object labels against the webhook's parsed ObjectSelector. Called by generic.Webhook.ShouldCallHook()."
    },
    {
      "path": "staging/src/k8s.io/apiserver/pkg/admission/plugin/webhook/predicates/rules/rules.go",
      "role": "webhook_predicate",
      "description": "Rules-based predicate. Matcher.Matches() checks scope, operation, API group, API version, and resource/subresource against a v1.RuleWithOperations. Also contains IsExemptAdmissionConfigurationResource() which short-circuits dispatch for webhook/policy configuration objects themselves."
    },
    {
      "path": "staging/src/k8s.io/apiserver/pkg/admission/plugin/webhook/matchconditions/matcher.go",
      "role": "webhook_predicate",
      "description": "CEL match-condition evaluator. matcher.Match() runs the compiled CEL filter expressions against the versioned admission attributes. Returns MatchResult{Matches: false} on any false condition, or an error/false depending on FailurePolicy when evaluation errors occur. Called by generic.Webhook.ShouldCallHook() when the webhook has MatchConditions."
    },
    {
      "path": "staging/src/k8s.io/apiserver/pkg/admission/plugin/webhook/matchconditions/interface.go",
      "role": "webhook_predicate",
      "description": "Matcher interface (Match method) and MatchResult struct used by the CEL match-condition layer."
    },
    {
      "path": "staging/src/k8s.io/apiserver/pkg/admission/plugin/webhook/mutating/reinvocationcontext.go",
      "role": "webhook_call_dispatch",
      "description": "webhookReinvokeContext: tracks reinvocation state for the mutating dispatcher. Records which webhooks have been invoked (AddReinvocableWebhookToPreviouslyInvoked), detects object mutations between invocations (IsOutputChangedSinceLastWebhookInvocation), and schedules re-invocation of earlier webhooks when a later one mutates the object (RequireReinvokingPreviouslyInvokedPlugins)."
    },
    {
      "path": "staging/src/k8s.io/apiserver/pkg/admission/plugin/webhook/initializer/initializer.go",
      "role": "plugin_initializer",
      "description": "PluginInitializer: admission.PluginInitializer for webhook plugins. Initialize() injects a ServiceResolver and an AuthenticationInfoResolverWrapper into any plugin that implements the corresponding Want* interfaces, wiring the HTTP client infrastructure used by both mutating and validating dispatchers."
    },
    {
      "path": "staging/src/k8s.io/apiserver/pkg/admission/plugin/webhook/config/kubeconfig.go",
      "role": "plugin_config",
      "description": "LoadConfig(): parses the optional WebhookAdmission config file (v1 or v1alpha1) to extract the kubeconfig file path used to authenticate webhook HTTP calls. Called by generic.NewWebhook() during plugin construction."
    },
    {
      "path": "staging/src/k8s.io/apiserver/pkg/admission/plugin/webhook/util/client_config.go",
      "role": "utility",
      "description": "HasAdmissionReviewVersion(): checks whether a given AdmissionReview version string is in the webhook's AdmissionReviewVersions list. Used by dispatchers when selecting the request/response version."
    }
  ]
}

